public void testReduceNegativeZero() {
    Fraction f = Fraction.getFraction(0, -100);
    Fraction result = f.reduce();
    assertEquals(0, result.getNumerator());
    assertEquals(1, result.getDenominator());
    assertSame(result, Fraction.ZERO);
}

public void testReduceLargeNumeratorWithGcd() {
    Fraction f = Fraction.getFraction(1000, 2500);
    Fraction result = f.reduce();
    assertEquals(2, result.getNumerator());
    assertEquals(5, result.getDenominator());
}

public void testReduceAlreadyReducedNegative() {
    Fraction f = Fraction.getFraction(-5, 7);
    Fraction result = f.reduce();
    assertEquals(-5, result.getNumerator());
    assertEquals(7, result.getDenominator());
    assertSame(f, result);
}
